export async function getGraphicsCapabilities() {
    let webgpu = false;
    try {
        webgpu = !!(await navigator.gpu.requestAdapter());
    }
    catch { }
    const gl = document.createElement('canvas').getContext('webgl2');
    gl?.getExtension('WEBGL_lose_context')?.loseContext();
    return { webgpu, webgl2: !!gl };
}
export function preferredRenderer(c) {
    if (c.webgpu) {
        return 'WebGPU';
    }
    if (c.webgl2) {
        return 'WebGL2';
    }
    return 'Canvas2D';
}
export function availableRenderers(c) {
    const list = [];
    if (c.webgpu) {
        list.push('WebGPU');
    }
    if (c.webgl2) {
        list.push('WebGL2');
    }
    list.push('Canvas2D');
    return list;
}
