import { cast, get, set } from './bit.js';
export const OFFSET_R = 24;
export const OFFSET_G = 16;
export const OFFSET_B = 8;
export const OFFSET_A = 0;
export function newColor(r, g, b, a) {
    return (r << OFFSET_R) + (g << OFFSET_G) + (b << OFFSET_B) + (a << OFFSET_A);
}
export function from(color) {
    return newColor(get(color, OFFSET_R), get(color, OFFSET_G), get(color, OFFSET_B), get(color, OFFSET_A));
}
export function toNumber(color) {
    return cast(color);
}
export function getRed(c) {
    return get(c, OFFSET_R);
}
export function getGreen(c) {
    return get(c, OFFSET_G);
}
export function getBlue(c) {
    return get(c, OFFSET_B);
}
export function getAlpha(c) {
    return get(c, OFFSET_A);
}
export function setRed(c, value) {
    return set(c, OFFSET_R, value);
}
export function setGreen(c, value) {
    return set(c, OFFSET_G, value);
}
export function setBlue(c, value) {
    return set(c, OFFSET_B, value);
}
export function setAlpha(c, value) {
    return set(c, OFFSET_A, value);
}
