export default function copyToClipboard(text, options = {}) {
    const format = options.format ?? 'text/plain';
    const useAsync = format === 'text/plain' && window.isSecureContext;
    if (useAsync) {
        void navigator.clipboard.writeText(text);
    }
    return useAsync ? true : execCommandCopy(text, format);
}
function execCommandCopy(text, format) {
    const selection = document.getSelection();
    const previousRange = selection && selection.rangeCount > 0 ? selection.getRangeAt(0) : undefined;
    const span = document.createElement('span');
    span.textContent = text;
    span.style.whiteSpace = 'pre';
    span.style.position = 'fixed';
    span.style.top = '0';
    span.style.left = '0';
    span.style.opacity = '0';
    document.body.append(span);
    const listener = (e) => {
        if (e.clipboardData) {
            e.clipboardData.clearData();
            e.clipboardData.setData(format, text);
        }
        e.preventDefault();
    };
    document.addEventListener('copy', listener);
    let success = false;
    try {
        const range = document.createRange();
        range.selectNodeContents(span);
        selection?.removeAllRanges();
        selection?.addRange(range);
        success = document.execCommand('copy');
    }
    catch (e) {
        console.error(e);
    }
    finally {
        document.removeEventListener('copy', listener);
        selection?.removeAllRanges();
        if (previousRange) {
            selection?.addRange(previousRange);
        }
        span.remove();
    }
    return success;
}
